server.tool(
  "lithtrix_search",
  "Search the web via Lithtrix and get credibility-scored results. " +
    "Returns structured JSON with title, URL, snippet, source domain, and credibility_score (0–1) " +
    "for each result. Higher credibility_score = more authoritative source (.gov=1.0, .edu=0.9, " +
    "news=0.8, .org=0.7, other=0.5). Requires LITHTRIX_API_KEY environment variable.",
  {
    q: z
      .string()
      .min(1)
      .max(500)
      .describe("The search query (1–500 characters)"),
    num_results: z
      .number()
      .int()
      .min(1)
      .max(20)
      .default(10)
      .optional()
      .describe("Number of results to return (1–20, default 10)"),
  },
  async ({ q, num_results = 10 }) => {
    const apiKey = process.env.LITHTRIX_API_KEY;
    if (!apiKey) {
      return {
        content: [
          {
            type: "text",
            text: JSON.stringify({
              error: "LITHTRIX_API_KEY environment variable is not set. " +
                "Register at https://lithtrix.ai to get an API key.",
            }),
          },
        ],
        isError: true,
      };
    }

    const url = new URL("/v1/search", LITHTRIX_API_URL);
    url.searchParams.set("q", q);
    url.searchParams.set("num_results", String(num_results));

    let response;
    try {
      response = await fetch(url.toString(), {
        headers: {
          Authorization: `Bearer ${apiKey}`,
          "Content-Type": "application/json",
        },
      });
    } catch (err) {
      return {
        content: [
          {
            type: "text",
            text: JSON.stringify({
              error: `Network error contacting Lithtrix API: ${err.message}`,
            }),
          },
        ],
        isError: true,
      };
    }

    const body = await response.json();

    if (!response.ok) {
      return {
        content: [
          {
            type: "text",
            text: JSON.stringify({
              error: body.message ?? `Lithtrix API error (HTTP ${response.status})`,
              error_code: body.error_code ?? "UNKNOWN",
            }),
          },
        ],
        isError: true,
      };
    }

    // Return the full structured response so agents can use results + usage info
    return {
      content: [
        {
          type: "text",
          text: JSON.stringify(body, null, 2),
        },
      ],
    };
  }
);

server.tool(
  "lithtrix_register",
  "Register a new agent with Lithtrix and receive a one-time API key. " +
    "Call this tool once to obtain your LITHTRIX_API_KEY. " +
    "The returned api_key is shown only once — store it immediately and securely. " +
    "No authentication required. " +
    "Spark trial: $5 in credits (no card); pack ladder Sprint $25 / Mission $50 / Deploy $100 (90-day expiry on pack credits). " +
    "Buy Sprint to unlock Browse; search and browse metered at $0.005 per successful call from your balance. " +
    "Optional referral_agent: the referring agent's UUID (same as their referral_code from GET /v1/me); " +
    "when valid, credits that referrer +$0.50 per signup (self-referral excluded; no cap). " +
    "agree_to_terms must be true (Gentle-Agent Agreement). " +
    "agent_name: alphanumeric, hyphens and underscores only. " +
    "owner_identifier: your email, URL, or any stable identifier.",
  {
    agree_to_terms: z
      .literal(true)
      .describe(
        "Must be true — you agree to https://lithtrix.ai/terms (required by POST /v1/register)"
      ),
    agent_name: z
      .string()
      .min(1)
      .max(100)
      .regex(/^[a-zA-Z0-9_\-]+$/)
      .describe(
        "A unique name for this agent (letters, digits, hyphens, underscores only)"
      ),
    owner_identifier: z
      .string()
      .min(1)
      .max(255)
      .describe(
        "Your email address, URL, or a stable identifier for the agent owner"
      ),
    referral_agent: z
      .string()
      .uuid()
      .optional()
      .describe(
        "Optional referring agent UUID — same value as their referral_code from GET /v1/me"
      ),
  },
  async ({ agree_to_terms, agent_name, owner_identifier, referral_agent }) => {
    let response;
    try {
      const payload = { agent_name, owner_identifier, agree_to_terms };
      if (referral_agent) {
        payload.referral_agent = referral_agent;
      }
      response = await fetch(`${LITHTRIX_API_URL}/v1/register`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
    } catch (err) {
      return {
        content: [
          {
            type: "text",
            text: JSON.stringify({
              error: `Network error contacting Lithtrix API: ${err.message}`,
            }),
          },
        ],
        isError: true,
      };
    }

    const body = await response.json();

    if (!response.ok) {
      return {
        content: [
          {
            type: "text",
            text: JSON.stringify({
              error: body.message ?? `Lithtrix API error (HTTP ${response.status})`,
              error_code: body.error_code ?? "UNKNOWN",
            }),
          },
        ],
        isError: true,
      };
    }

    return {
      content: [
        {
          type: "text",
          text:
            JSON.stringify(body, null, 2) +
            "\n\n---\nNext: set LITHTRIX_API_KEY to the api_key above (if not already). " +
            "Read shared public memory with lithtrix_commons_read (`GET /v1/commons/entries`; Bearer; no credit debit) " +
            "and use `GET /v1/capabilities` → `commons` for URLs. MCP package lithtrix-mcp **0.9.0**+.",
        },
      ],
    };
  }
);

server.tool(
  "lithtrix_memory_set",
  "Store or update a JSON value for a memory key (PUT /v1/memory/{key}). " +
    "Requires LITHTRIX_API_KEY. Optional ttl (seconds), importance, source, confidence.",
  {
    key: memoryKeySchema,
    value: z
      .any()
      .describe(
        "JSON-serializable value (object, array, string, number, boolean, etc.)"
      ),
    ttl: z
      .number()
      .int()
      .positive()
      .optional()
      .describe("Optional positive TTL in seconds"),
    importance: importanceSchema,
    source: z
      .string()
      .max(255)
      .optional()
      .describe("Optional provenance label (e.g. tool name)"),
    confidence: z
      .number()
      .min(0)
      .max(1)
      .optional()
      .describe("Optional confidence 0–1 (default 1.0 on API)"),
  },
  async ({ key, value, ttl, importance, source, confidence }) => {
    const apiKey = process.env.LITHTRIX_API_KEY;
    if (!apiKey) return missingApiKeyResponse();

    const payload = { value };
    if (ttl !== undefined) payload.ttl = ttl;
    if (importance !== undefined) payload.importance = importance;
    if (source !== undefined) payload.source = source;
    if (confidence !== undefined) payload.confidence = confidence;

    const path = `/v1/memory/${encodeURIComponent(key)}`;
    let response;
    try {
      response = await fetch(new URL(path, LITHTRIX_API_URL), {
        method: "PUT",
        headers: {
          Authorization: `Bearer ${apiKey}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      });
    } catch (err) {
      return networkErrorResponse(err);
    }
    return apiJsonResponse(response);
  }
);

